class Controls{#dir={left:!1,right:!1,up:!1,down:!1,forward:!1,backward:!1};constructor(){this.#keyDownEvtListener(),this.#keyUpEvtListener()}get getcontrols(){const{left:left,right:right,up:up,down:down,forward:forward,backward:backward}=this.#dir;return{left:left,right:right,up:up,down:down,forward:forward,backward:backward}}#keyDownEvtListener(){document.addEventListener("keydown",(e=>{switch(e.key){case"ArrowLeft":return void(this.#dir.left=!0);case"ArrowRight":return void(this.#dir.right=!0);case"ArrowUp":return void(this.#dir.forward=!0);case"ArrowDown":return void(this.#dir.backward=!0)}}))}#keyUpEvtListener(){document.addEventListener("keyup",(e=>{switch(e.key){case"ArrowLeft":return void(this.#dir.left=!1);case"ArrowRight":return void(this.#dir.right=!1);case"ArrowUp":return void(this.#dir.forward=!1);case"ArrowDown":return void(this.#dir.backward=!1)}}))}}export{Controls};